#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    FILE *ulaz;
    int broj, suma = 0;
    char niz[50];

    ulaz = fopen("datoteka.txt", "r");
    if (ulaz == NULL) {
        printf("Otvaranje datoteke datoteka.txt nije uspjelo!\n");
        return 1;
    }

    printf("Lista stringova: ");
    while (fscanf(ulaz, "%d", &broj) == 1) {
        /* uklanjamo prvi whitespace nakon broja */
        fgetc(ulaz);
        if (fgets(niz, sizeof(niz), ulaz) != NULL) {
            /* uklonimo novi red na kraju stringa ako postoji */
            niz[strcspn(niz, "\n")] = '\0';
            suma += broj;
            printf("%s\n", niz);
        }
    }

    printf("\nUkupna suma brojeva: %d\n", suma);

    fclose(ulaz);
    return 0;
}
